<script setup lang="ts">
import { ref, computed } from "vue";
import { usePhotosStore } from "@renderer/stores/photos";
import { usePreferenceStore } from "@renderer/stores/preference";
import { storeToRefs } from "pinia";
import { getFolderFiles } from "@renderer/utils/folder-tree";

type Card = {
    title: string;
    parts: string[];
    images: Image[];
};

type Image = {
    key: string;
    src: string;
    fallback: string;
};
const store = usePhotosStore();

const { currentFolder } = storeToRefs(store);
const { thumbnailSize } = storeToRefs(usePreferenceStore());

const fallback = ref(
    "data:image/png;base64,",
);

const cards = computed(() => {
    const cards: Card[] = [];
    const images: Image[] = [];
    getFolderFiles(currentFolder.value)?.forEach((file) => {
        if (file.path.indexOf(currentFolder.value) >= 0) {
            images.push({
                key: file.path,
                src: `file://${file.thumbnail}`,
                fallback: `file://${file.path}`,
            });
        }
    });

    cards.push({
        title: currentFolder.value,
        images,
        parts: currentFolder.value.split("/"),
    });

    return cards;
});
</script>

<template>
    <a-card v-for="card in cards" :key="card.title">
        <template #title>
            <a-breadcrumb style="margin: 16px 0">
                <a-breadcrumb-item v-for="part in card.parts" :key="part">{{
                    part
                }}</a-breadcrumb-item>
            </a-breadcrumb>
        </template>
        <div class="image-list">
            <ul v-if="card.images.length > 0">
                <li
                    v-for="image in card.images"
                    :key="image.key"
                    :width="150"
                    :height="150"
                    class="image-item"
                >
                    <a-image
                        :width="thumbnailSize"
                        :height="thumbnailSize"
                        :src="image.src"
                        :fallback="image.fallback"
                    />
                </li>
            </ul>
            <a-empty v-else />
        </div>
    </a-card>
</template>
<style lang="less">
.image-list {
    height: 100%;
    overflow: auto;

    ul {
        list-style-type: none;
        li {
            .ant-image {
                overflow: hidden;
            }
            margin-top: 0px;
            margin-left: 0px;
            margin-right: 10px;
            margin-bottom: 10px;
            float: left;
            box-shadow: 1px 1px 2px #777;
            border-radius: 1px;
            background-color: white;
            white-space: nowrap;
            word-break: keep-all;
            text-overflow: ellipsis;
            overflow: hidden;
            transition: all 0.5s ease;
        }
    }
}
</style>
